questions.questionText:
What is the output?

// math.js
export const PI = 3.14;
export const E = 2.71;

// main.js
import { PI, E as EULER } from './math.js';
console.log(PI, EULER);

What is the output?

// a.js
export let count = 0;
export function increment() { count++; }

// b.js
import { count, increment } from './a.js';
console.log(count);  // line X
increment();
console.log(count);  // line Y

What is the output?

// counter.js
let count = 0;
export function getCount() { return count; }
export function setCount(n) { count = n; }

// main.js
import { getCount, setCount } from './counter.js';
setCount(5);
import { getCount as gc } from './counter.js';
console.log(gc());
